/**
 * `dorkos package validate-marketplace <path>`
 *
 * Validates a marketplace.json file against the schema from @dorkos/marketplace.
 * Used by the dorkos-community GitHub Actions workflow on every PR.
 *
 * Exit codes:
 *   0 — valid
 *   1 — file missing or invalid JSON
 *   2 — schema validation failed
 *
 * @module commands/package-validate-marketplace
 */
import fs from 'node:fs/promises';
import path from 'node:path';
import { parseMarketplaceJson } from '@dorkos/marketplace';

export interface ValidateMarketplaceArgs {
  path: string;
}

export function parseValidateMarketplaceArgs(rawArgs: string[]): ValidateMarketplaceArgs {
  const positional = rawArgs.filter((a) => !a.startsWith('-'));
  if (positional.length === 0) {
    throw new Error('Usage: dorkos package validate-marketplace <path>');
  }
  return { path: positional[0] };
}

export async function runValidateMarketplace(args: ValidateMarketplaceArgs): Promise<number> {
  const absPath = path.resolve(process.cwd(), args.path);
  let content: string;
  try {
    content = await fs.readFile(absPath, 'utf8');
  } catch (err) {
    process.stderr.write(`Failed to read ${absPath}: ${(err as Error).message}\n`);
    return 1;
  }

  const result = parseMarketplaceJson(content);
  if (!result.ok) {
    process.stderr.write(`Validation failed: ${result.error}\n`);
    return 2;
  }

  process.stdout.write(`OK: ${absPath} (${result.marketplace.plugins.length} packages)\n`);
  return 0;
}
```

## package-validate-remote.ts

```typescript
/**
 * `dorkos package validate-remote <github-url>`
 *
 * Shallow-clones a package repo into a temp dir and runs the same validations
 * as `dorkos package validate`. Cleans up the temp dir on exit.
 *
 * Exit codes:
 *   0 — valid
 *   1 — clone failed
 *   2 — validation failed
 *
 * @module commands/package-validate-remote
 */
import { spawn } from 'node:child_process';
import fs from 'node:fs/promises';
import os from 'node:os';
import path from 'node:path';
import { validatePackage } from '@dorkos/marketplace';

export interface ValidateRemoteArgs {
  url: string;
}

export function parseValidateRemoteArgs(rawArgs: string[]): ValidateRemoteArgs {
  const positional = rawArgs.filter((a) => !a.startsWith('-'));
  if (positional.length === 0) {
    throw new Error('Usage: dorkos package validate-remote <github-url>');
  }
  return { url: positional[0] };
}

export async function runValidateRemote(args: ValidateRemoteArgs): Promise<number> {
  const tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'dorkos-validate-'));
  try {
    const cloned = await shallowClone(args.url, tmpDir);
    if (!cloned) {
      process.stderr.write(`Clone failed: ${args.url}\n`);
      return 1;
    }

    const result = await validatePackage(tmpDir);
    if (!result.ok) {
      process.stderr.write(`Validation failed: ${result.errors.join('; ')}\n`);
      return 2;
    }
    process.stdout.write(`OK: ${args.url}\n`);
    return 0;
  } finally {
    await fs.rm(tmpDir, { recursive: true, force: true });
  }
}

function shallowClone(url: string, dest: string): Promise<boolean> {
  return new Promise((resolve) => {
    const child = spawn('git', ['clone', '--depth', '1', url, dest], { stdio: 'inherit' });
    child.on('exit', (code) => resolve(code === 0));
    child.on('error', () => resolve(false));
  });
}
```

